{"questions":[
  {
    "label":"Review friction",
    "name":"I wanted to ask about the design-system PR — what made that one hard to land?",
    "description":"Surfaces the specific source of friction in the rework-heavy PR without assuming fault.",
    "purpose":"topic",
    "axis_effects":[{"axis":"clarity","delta":3},{"axis":"engagement","delta":1}]
  },
  {
    "label":"Review turnaround",
    "name":"What has been slowing your PR reviews down lately?",
    "description":"Looks for concrete bottlenecks in the review loop and whether they are process, dependency, or confidence related.",
    "purpose":"topic",
    "axis_effects":[{"axis":"clarity","delta":3},{"axis":"wellbeing","delta":1}]
  },
  {
    "label":"Commit thinning",
    "name":"What changed in how you're approaching your work over the last few weeks?",
    "description":"Invites a narrative about the shift in commit volume and cadence without making it about performance.",
    "purpose":"wellbeing",
    "axis_effects":[{"axis":"wellbeing","delta":3},{"axis":"engagement","delta":1}]
  },
  {
    "label":"Pacing tradeoff",
    "name":"What have you had to drop or slow down to keep up with everything on your plate?",
    "description":"Surfaces hidden workload pressure and the trade-offs they are making to stay afloat.",
    "purpose":"wellbeing",
    "axis_effects":[{"axis":"wellbeing","delta":3},{"axis":"clarity","delta":1}]
  },
  {
    "label":"Focus drain",
    "name":"Where is your attention getting pulled away from the work most often?",
    "description":"Finds recurring interruptions, context switching, or personal drains affecting output and focus.",
    "purpose":"wellbeing",
    "axis_effects":[{"axis":"wellbeing","delta":1},{"axis":"clarity","delta":1}]
  },
  {
    "label":"Ownership shift",
    "name":"What parts of the frontend work still feel worth leaning into for you?",
    "description":"Checks whether motivation and ownership are still present in specific areas of the role.",
    "purpose":"competency",
    "axis_effects":[{"axis":"engagement","delta":3},{"axis":"growth","delta":1}]
  },
  {
    "label":"Stretch gap",
    "name":"Where do you feel like you're not getting enough stretch right now?",
    "description":"Surfaces plateau, under-challenge, or a mismatch between current tasks and growth needs.",
    "purpose":"competency",
    "axis_effects":[{"axis":"growth","delta":3},{"axis":"engagement","delta":1}]
  },
  {
    "label":"Feedback texture",
    "name":"How has the feedback on your recent work landed for you?",
    "description":"Explores whether feedback is useful, discouraging, or unclear in practice.",
    "purpose":"topic",
    "axis_effects":[{"axis":"clarity","delta":1},{"axis":"growth","delta":3}]
  },
  {
    "label":"Support needed",
    "name":"What kind of support would make the next couple of weeks easier for you?",
    "description":"Opens up practical support needs without presuming the problem is personal or performance-related.",
    "purpose":"wellbeing",
    "axis_effects":[{"axis":"wellbeing","delta":1},{"axis":"clarity","delta":3}]
  },
  {
    "label":"Next step focus",
    "name":"What do you want to get back to feeling steady on first?",
    "description":"Gets at the most immediate priority for recovery or re-engagement from their point of view.",
    "purpose":"wellbeing",
    "axis_effects":[{"axis":"wellbeing","delta":3},{"axis":"engagement","delta":1}]
  }
]}
